exercises.solution_code:
#include <iostream>
#include <iomanip>

int main()
{
    double value{};
    std::cin >> value;

    std::cout << std::defaultfloat;
    std::cout << "Default: " << value << '\n';

    std::cout << std::fixed << std::setprecision(6);
    std::cout << "Fixed: " << value << '\n';

    std::cout << std::scientific << std::setprecision(6);
    std::cout << "Scientific: " << value << '\n';

    return 0;
}

