exercises.solution_code:
#include <iostream>
#include <iomanip>
#include <cmath>

int main()
{
    double sum1 = 0.1 + 0.2;
    double sum2 = 1.0 / 3.0 * 3.0;

    double epsilon = 1e-9;

    std::cout << std::fixed << std::setprecision(17);
    std::cout << "0.1 + 0.2 = " << sum1 << '\n';

    std::cout << std::boolalpha;
    std::cout << "Exact equal to 0.3: " << (sum1 == 0.3) << '\n';
    std::cout << "Nearly equal to 0.3: " << (std::abs(sum1 - 0.3) < epsilon) << '\n';

    std::cout << std::fixed << std::setprecision(17);
    std::cout << "1.0/3.0*3.0 = " << sum2 << '\n';

    std::cout << "Exact equal to 1.0: " << (sum2 == 1.0) << '\n';
    std::cout << "Nearly equal to 1.0: " << (std::abs(sum2 - 1.0) < epsilon) << '\n';

    return 0;
}
